import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Radio, Info, Volume2, VolumeX, Volume1, Languages } from 'lucide-react';
import PlayerControls from './components/PlayerControls';
import Visualizer from './components/Visualizer';
import { SONGS_PLAYLIST, TRANSLATIONS } from './constants';
import { getMusicInsight } from './services/geminiService';
import { Song, Language } from './types';

const STREAM_URL = "https://radio.dukahosting.com/8004/stream";
const ROTATION_INTERVAL = 40000; // 40 seconds

const App: React.FC = () => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [volume, setVolume] = useState(0.8);
  const [isMuted, setIsMuted] = useState(false);
  const [lang, setLang] = useState<Language>('mk');
  const [currentSong, setCurrentSong] = useState<Song>(SONGS_PLAYLIST[0]);
  const [insight, setInsight] = useState<string>(SONGS_PLAYLIST[0].descriptionMk);
  const [isLoadingInsight, setIsLoadingInsight] = useState(false);
  const [isTransitioning, setIsTransitioning] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const insightTimeoutRef = useRef<number | null>(null);
  const t = TRANSLATIONS[lang];

  // Initialize Audio
  useEffect(() => {
    audioRef.current = new Audio(STREAM_URL);
    audioRef.current.crossOrigin = "anonymous";

    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current.src = "";
        audioRef.current = null;
      }
    };
  }, []);

  // Handle Playback
  useEffect(() => {
    if (!audioRef.current) return;

    if (isPlaying) {
      audioRef.current.src = STREAM_URL;
      audioRef.current.load();
      const playPromise = audioRef.current.play();
      if (playPromise !== undefined) {
        playPromise.catch(error => {
          console.error("Playback failed:", error);
          setIsPlaying(false);
        });
      }
    } else {
      audioRef.current.pause();
      audioRef.current.src = "";
    }
  }, [isPlaying]);

  // Handle Volume
  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = isMuted ? 0 : volume;
    }
  }, [volume, isMuted]);

  // Rotate songs randomly every 40 seconds
  const cycleSongs = useCallback(() => {
    let randomIndex;
    do {
      randomIndex = Math.floor(Math.random() * SONGS_PLAYLIST.length);
    } while (SONGS_PLAYLIST.length > 1 && SONGS_PLAYLIST[randomIndex].title === currentSong.title);

    setIsTransitioning(true);

    // Wait for the fade-out duration before changing content
    setTimeout(() => {
      setCurrentSong(SONGS_PLAYLIST[randomIndex]);
      setIsTransitioning(false);
    }, 600);
  }, [currentSong]);

  useEffect(() => {
    let timer: any;
    if (isPlaying) {
      timer = setInterval(() => {
        cycleSongs();
      }, ROTATION_INTERVAL); 
    }
    return () => clearInterval(timer);
  }, [isPlaying, cycleSongs]);

  // Fetch or set description/insight
  useEffect(() => {
    if (insightTimeoutRef.current) {
      window.clearTimeout(insightTimeoutRef.current);
    }

    const updateInsight = async () => {
      setIsLoadingInsight(true);

      const hardcodedDescription = lang === 'mk' ? currentSong.descriptionMk : currentSong.descriptionEn;

      if (hardcodedDescription) {
        setInsight(hardcodedDescription);
        setIsLoadingInsight(false);
      } else {
        const newInsight = await getMusicInsight(currentSong.title, currentSong.artist, lang);
        setInsight(newInsight);
        setIsLoadingInsight(false);
      }
    };

    insightTimeoutRef.current = window.setTimeout(updateInsight, 300);

    return () => {
      if (insightTimeoutRef.current) window.clearTimeout(insightTimeoutRef.current);
    };
  }, [currentSong, lang]);

  const togglePlay = () => setIsPlaying(!isPlaying);
  const toggleMute = () => setIsMuted(!isMuted);
  const toggleLang = () => setLang(prev => prev === 'mk' ? 'en' : 'mk');

  const renderVolumeIcon = () => {
    if (isMuted || volume === 0) return <VolumeX size={14} />;
    if (volume < 0.5) return <Volume1 size={14} />;
    return <Volume2 size={14} />;
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-between stone-gradient overflow-hidden px-6 selection:bg-stone-500/30">

      {/* Language Toggle */}
      <div className="absolute top-8 right-8 z-20">
        <button 
          onClick={toggleLang}
          className="flex items-center gap-2 text-[10px] uppercase tracking-[0.2em] text-stone-500 hover:text-stone-300 transition-all duration-300 px-3 py-1.5 rounded-full border border-stone-800/50 bg-stone-900/20 backdrop-blur-sm"
        >
          <Languages size={12} className="opacity-70" />
          <span className={lang === 'mk' ? 'text-stone-100 font-bold' : ''}>MK</span>
          <span className="text-stone-800">|</span>
          <span className={lang === 'en' ? 'text-stone-100 font-bold' : ''}>EN</span>
        </button>
      </div>

      {/* Header */}
      <header className="pt-16 text-center w-full max-w-4xl z-10">
        <div className="flex justify-center mb-6">
          <div className="w-12 h-[1px] bg-stone-700 self-center"></div>
          <Radio className="mx-6 w-5 h-5 text-stone-500" />
          <div className="w-12 h-[1px] bg-stone-700 self-center"></div>
        </div>
        <h1 className="font-serif text-4xl md:text-6xl lg:text-7xl font-light tracking-wide text-stone-100 mb-4 drop-shadow-sm">
          {t.stationName}
        </h1>
        <p className="font-sans text-xs md:text-sm uppercase tracking-[0.3em] text-stone-400 font-medium opacity-80">
          {t.slogan}
        </p>
      </header>

      {/* Main Content */}
      <main className="flex flex-col items-center justify-center flex-grow py-8 w-full max-w-2xl text-center z-10">

        {/* Status: Above Play Button */}
        <div className={`mb-6 flex items-center justify-center gap-2 transition-all duration-700 ${isPlaying ? 'opacity-100 transform translate-y-0' : 'opacity-40 transform translate-y-1'}`}>
          <span className={`w-1.5 h-1.5 rounded-full ${isPlaying ? 'bg-red-500 animate-pulse' : 'bg-stone-600'}`}></span>
          <h2 className="text-stone-500 text-[10px] uppercase tracking-[0.25em]">
            {isPlaying ? t.live : t.offline}
          </h2>
        </div>

        <div className="mb-12 flex flex-col items-center gap-8">
          <PlayerControls isPlaying={isPlaying} togglePlay={togglePlay} />

          {/* Subtle Volume Control */}
          <div className="group flex items-center gap-4 transition-opacity duration-300 opacity-60 hover:opacity-100">
            <button 
              onClick={toggleMute} 
              className="text-stone-400 hover:text-stone-200 transition-colors"
              aria-label={isMuted ? t.unmute : t.mute}
            >
              {renderVolumeIcon()}
            </button>
            <div className="w-24 flex items-center">
              <input 
                type="range" 
                min="0" 
                max="1" 
                step="0.01" 
                value={isMuted ? 0 : volume} 
                onChange={(e) => {
                  setVolume(parseFloat(e.target.value));
                  if (isMuted) setIsMuted(false);
                }}
                className="subtle-slider w-full cursor-pointer"
              />
            </div>
          </div>
        </div>

        {/* Status and Visualizer */}
        <section className={`transition-all duration-1000 w-full ${isPlaying ? 'opacity-100 transform translate-y-0' : 'opacity-60 transform translate-y-1'}`}>
          <div className={`space-y-2 mb-8 transition-all duration-700 ease-in-out ${isTransitioning ? 'opacity-0 scale-[0.98] blur-sm' : 'opacity-100 scale-100 blur-0'}`}>
            <h2 className="text-stone-500 text-[10px] uppercase tracking-[0.25em] mb-4 block">
              {t.aboutSongLabel}
            </h2>
            <div className="min-h-[80px]">
              <p className="font-serif text-2xl md:text-4xl text-stone-200 leading-tight">
                {isPlaying ? currentSong.title : t.listenLive}
              </p>
              <p className="text-stone-500 font-light text-base md:text-xl mt-2">
                {isPlaying ? currentSong.artist : t.folkMusic}
              </p>
            </div>
          </div>

          <Visualizer active={isPlaying && !isTransitioning} />

          {/* Editor's Note */}
          <div className="mt-12 max-w-lg mx-auto min-h-[140px] flex flex-col items-center">
            <div className={`transition-all duration-700 ease-in-out ${isLoadingInsight || isTransitioning ? 'opacity-0 scale-[0.98] blur-sm' : 'opacity-100 scale-100 blur-0'} ${!isPlaying ? 'opacity-50 grayscale' : 'opacity-100'}`}>
              <span className="text-[10px] uppercase tracking-[0.3em] text-stone-600 mb-4 block">{t.editorsNote}</span>
              <p className="italic text-stone-400 font-light text-sm md:text-base leading-relaxed relative px-8 max-w-md">
                <span className="absolute left-0 top-0 text-3xl text-stone-800 font-serif leading-none">“</span>
                {insight}
                <span className="absolute right-0 bottom-0 text-3xl text-stone-800 font-serif leading-none">”</span>
              </p>
            </div>
          </div>
        </section>
      </main>

      {/* About Section */}
