import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Generates an authentic Macedonian background image using Gemini 2.5 Flash Image.
 * Returns a base64 data URL of the generated image.
 */
export async function generateMacedonianBackground(): Promise<string | null> {
  const prompts = [
    "Lake Ohrid with Saint John at Kaneo, sunset lighting, realistic photo, wide shot, cinematic, peaceful.",
    "Traditional Macedonian stone house in Krushevo, morning mist, hyper-realistic, architectural photography.",
    "Ancient ruins of Heraclea Lyncestis, dramatic shadows, wide panoramic view, professional photography.",
    "Macedonian mountain landscape, Korab peak, wild flowers in foreground, blue sky, epic nature photography.",
    "Old Bazaar in Skopje, cobbled streets, warm lantern lighting, night shot, authentic and moody.",
    "Vardar river canyon, Matka lake, emerald water, towering cliffs, high quality aerial photography."
  ];

  const selectedPrompt = prompts[Math.floor(Math.random() * prompts.length)];
  const finalPrompt = `A high quality, atmospheric background image for a traditional music website: ${selectedPrompt} Keep the tone sophisticated and cultural. 16:9 aspect ratio.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: [{ parts: [{ text: finalPrompt }] }],
      config: {
        imageConfig: {
          aspectRatio: "16:9"
        }
      },
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        const base64Data = part.inlineData.data;
        return `data:image/png;base64,${base64Data}`;
      }
    }

    return null;
  } catch (error) {
    console.error("Error generating background image:", error);
    return null;
  }
}

