import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Generates an authentic Macedonian background image using Gemini 2.5 Flash Image.
 * Returns a base64 data URL of the generated image.
 */
export async function generateMacedonianBackground(): Promise<string | null> {
  const prompts = [
    "Award-winning professional photography of Lake Ohrid sunset, Saint John at Kaneo church on the cliff, crystal clear water, high dynamic range, 8k resolution, cinematic lighting.",
    "Hyper-realistic architectural photography of old stone houses in Krushevo, morning dew, cobblestone streets, vibrant Macedonian textures, high fidelity.",
    "Breathtaking landscape photo of Mount Korab peaks, emerald green meadows, blue sky with wispy clouds, sharp focus, professional nature photography.",
    "Cinematic night photography of the Old Bazaar in Skopje, glowing street lamps, reflections on wet cobbles, authentic atmosphere, high resolution.",
    "Wide angle landscape shot of Matka Canyon, turquoise river water, towering limestone cliffs, lush vegetation, ultra-realistic detailed textures.",
    "The Monastery of Saint Naum at the springs of Lake Ohrid, serene water reflections, historic brickwork, sunny day, professional travel photography.",
    "Pelister national park 'Eyes of Pelister' glacial lakes, reflection of the mountain peaks in the water, crisp air, hyper-detailed photography."
  ];

  const selectedPrompt = prompts[Math.floor(Math.random() * prompts.length)];
  const finalPrompt = `An ultra-realistic, award-winning 8k photograph for a high-end cultural documentary: ${selectedPrompt} No artistic filters, no illustrations, purely sharp and clear photography. 16:9 aspect ratio.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: [{ parts: [{ text: finalPrompt }] }],
      config: {
        imageConfig: {
          aspectRatio: "16:9"
        }
      },
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        const base64Data = part.inlineData.data;
        return `data:image/png;base64,${base64Data}`;
      }
    }

    return null;
  } catch (error) {
    console.error("Error generating background image:", error);
    return null;
  }
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Radio, Info, Languages, Loader2 } from 'lucide-react';
import PlayerControls from './components/PlayerControls';
