import { getMusicInsight } from './services/geminiService';
import { generateMacedonianBackground } from './services/imageService';
import { Song, Language } from './types';

const STREAM_URL = "https://radio.dukahosting.com/8004/stream";
const ROTATION_INTERVAL = 40000; // 40 seconds
const FADE_DURATION = 2000; // 2 seconds for smooth transition

const App: React.FC = () => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [volume] = useState(1.0); // Set to maximum by default
  const [lang, setLang] = useState<Language>('mk');
  const [currentSong, setCurrentSong] = useState<Song>(SONGS_PLAYLIST[0]);
  const [insight, setInsight] = useState<string>(SONGS_PLAYLIST[0].descriptionMk);
  const [isLoadingInsight, setIsLoadingInsight] = useState(false);
  const [isTransitioning, setIsTransitioning] = useState(false);

  // Background states
  const [bgImage, setBgImage] = useState<string | null>(null);
  const [isGeneratingBg, setIsGeneratingBg] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const insightTimeoutRef = useRef<number | null>(null);
  const t = TRANSLATIONS[lang];

  // Initialize Audio and Initial Background
  useEffect(() => {
    audioRef.current = new Audio(STREAM_URL);
    audioRef.current.crossOrigin = "anonymous";
    audioRef.current.volume = volume;

    // Auto-generate background on start
    handleInitialBg();

    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current.src = "";
        audioRef.current = null;
      }
    };
  }, []);

  const handleInitialBg = async () => {
    setIsGeneratingBg(true);
    try {
      const url = await generateMacedonianBackground();
      if (url) {
        setBgImage(url);
      }
    } catch (err) {
      console.error("Bg generation failed", err);
    } finally {
      setIsGeneratingBg(false);
    }
  };

  // Handle Playback
  useEffect(() => {
    if (!audioRef.current) return;

    if (isPlaying) {
      audioRef.current.src = STREAM_URL;
      audioRef.current.load();
      const playPromise = audioRef.current.play();
      if (playPromise !== undefined) {
        playPromise.catch(error => {
          console.error("Playback failed:", error);
          setIsPlaying(false);
        });
      }
    } else {
      audioRef.current.pause();
      audioRef.current.src = "";
    }
  }, [isPlaying]);

  // Rotate songs randomly every 40 seconds
  const cycleSongs = useCallback(() => {
    let randomIndex;
    do {
      randomIndex = Math.floor(Math.random() * SONGS_PLAYLIST.length);
    } while (SONGS_PLAYLIST.length > 1 && SONGS_PLAYLIST[randomIndex].title === currentSong.title);

    setIsTransitioning(true);

    setTimeout(() => {
      setCurrentSong(SONGS_PLAYLIST[randomIndex]);
      setIsTransitioning(false);
    }, FADE_DURATION / 2);
  }, [currentSong]);

  useEffect(() => {
    let timer: any;
    if (isPlaying) {
      timer = setInterval(() => {
        cycleSongs();
      }, ROTATION_INTERVAL); 
    }
    return () => clearInterval(timer);
  }, [isPlaying, cycleSongs]);

  // Fetch or set description/insight
  useEffect(() => {
    if (insightTimeoutRef.current) {
      window.clearTimeout(insightTimeoutRef.current);
    }

    const updateInsight = async () => {
      setIsLoadingInsight(true);

      const hardcodedDescription = lang === 'mk' ? currentSong.descriptionMk : currentSong.descriptionEn;

      if (hardcodedDescription) {
        setInsight(hardcodedDescription);
        setIsLoadingInsight(false);
      } else {
        const newInsight = await getMusicInsight(currentSong.title, currentSong.artist, lang);
        setInsight(newInsight);
        setIsLoadingInsight(false);
      }
    };

    insightTimeoutRef.current = window.setTimeout(updateInsight, 300);

    return () => {
      if (insightTimeoutRef.current) window.clearTimeout(insightTimeoutRef.current);
    };
  }, [currentSong, lang]);

  const togglePlay = () => setIsPlaying(!isPlaying);
  const toggleLang = () => setLang(prev => prev === 'mk' ? 'en' : 'mk');

  return (
    <div className="relative min-h-screen flex flex-col items-center justify-between stone-gradient overflow-hidden px-6 selection:bg-stone-500/30">

      {/* Real Photography Background Layer */}
      <div 
        className={`fixed inset-0 z-0 transition-all duration-[4000ms] ease-in-out pointer-events-none ${bgImage ? 'opacity-100' : 'opacity-0'}`}
        style={{
          backgroundImage: bgImage ? `url(${bgImage})` : 'none',
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          filter: 'none'
        }}
      />

      {/* Dark overlay for text readability */}
      <div className="fixed inset-0 z-0 bg-black/60 pointer-events-none" />

      {/* Language Controls */}
      <div className="absolute top-8 right-8 z-20 flex flex-col items-end gap-3">
        <button 
          onClick={toggleLang}
          className="flex items-center gap-2 text-[10px] uppercase tracking-[0.2em] text-stone-300 hover:text-white transition-all duration-300 px-3 py-1.5 rounded-full border border-white/10 bg-black/40 backdrop-blur-md shadow-lg"
        >
          <Languages size={12} className="opacity-70" />
          <span className={lang === 'mk' ? 'text-white font-bold' : 'text-stone-400'}>MK</span>
          <span className="text-stone-700">|</span>
          <span className={lang === 'en' ? 'text-white font-bold' : 'text-stone-400'}>EN</span>
        </button>

        {isGeneratingBg && (
          <div className="flex items-center gap-2 text-[9px] uppercase tracking-widest text-white/50 animate-pulse px-3">
             <Loader2 size={10} className="animate-spin" />
             <span>{lang === 'mk' ? 'Вчитувам амбиент...' : 'Loading ambient...'}</span>
          </div>
        )}
      </div>

      {/* Header */}
      <header className="pt-16 text-center w-full max-w-4xl z-10">
        <div className="flex justify-center mb-6">
          <div className="w-12 h-[1px] bg-white/20 self-center"></div>
          <Radio className="mx-6 w-5 h-5 text-stone-400" />
          <div className="w-12 h-[1px] bg-white/20 self-center"></div>
        </div>
        <h1 className="font-serif text-4xl md:text-6xl lg:text-7xl font-light tracking-wide text-white mb-4 drop-shadow-2xl">
          {t.stationName}
        </h1>
        <p className="font-sans text-xs md:text-sm uppercase tracking-[0.3em] text-stone-300 font-medium opacity-90 drop-shadow-sm">
          {t.slogan}
        </p>
      </header>

      {/* Main Content */}
      <main className="flex flex-col items-center justify-center flex-grow py-8 w-full max-w-2xl text-center z-10">

        {/* Status indicator */}
        <div className={`mb-6 flex items-center justify-center gap-2 transition-all duration-700 ${isPlaying ? 'opacity-100 transform translate-y-0' : 'opacity-60 transform translate-y-1'}`}>
          <span className={`w-1.5 h-1.5 rounded-full ${isPlaying ? 'bg-red-500 animate-pulse shadow-[0_0_8px_rgba(239,68,68,0.8)]' : 'bg-stone-600'}`}></span>
          <h2 className="text-stone-300 text-[10px] uppercase tracking-[0.25em] font-semibold drop-shadow-sm">
            {isPlaying ? t.live : t.offline}
          </h2>
        </div>

        <div className="mb-12 flex flex-col items-center gap-8">
          <PlayerControls isPlaying={isPlaying} togglePlay={togglePlay} />
        </div>

        {/* Info and Visualizer */}
        <section className={`transition-all duration-1000 w-full ${isPlaying ? 'opacity-100 transform translate-y-0' : 'opacity-70 transform translate-y-1'}`}>
          <div className={`space-y-2 mb-8 transition-all ease-in-out`} style={{ transitionDuration: `${FADE_DURATION / 2}ms`, opacity: isTransitioning ? 0 : 1, transform: isTransitioning ? 'scale(0.98)' : 'scale(1)', filter: isTransitioning ? 'blur(4px)' : 'blur(0)' }}>
            <h2 className="text-stone-400 text-[10px] uppercase tracking-[0.25em] mb-4 block font-medium">
              {t.aboutSongLabel}
            </h2>
            <div className="min-h-[80px]">
              <p className="font-serif text-2xl md:text-4xl text-white leading-tight drop-shadow-2xl">
                {isPlaying ? currentSong.title : t.listenLive}
              </p>
              <p className="text-stone-300 font-light text-base md:text-xl mt-2 drop-shadow-md">
                {isPlaying ? currentSong.artist : t.folkMusic}
              </p>
            </div>
          </div>

          <Visualizer active={isPlaying && !isTransitioning} />

          {/* Editor's Note */}
          <div className="mt-12 max-w-lg mx-auto min-h-[140px] flex flex-col items-center">
            <div className={`transition-all ease-in-out ${!isPlaying ? 'opacity-50 grayscale' : 'opacity-100'}`} style={{ transitionDuration: `${FADE_DURATION / 2}ms`, opacity: (isLoadingInsight || isTransitioning) ? 0 : 1, transform: (isLoadingInsight || isTransitioning) ? 'scale(0.98)' : 'scale(1)', filter: (isLoadingInsight || isTransitioning) ? 'blur(4px)' : 'blur(0)' }}>
