export type Language = 'mk' | 'en' | 'ru';

import { GoogleGenAI } from "@google/genai";
import { Language } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Simple in-memory cache to prevent repeated calls for the same song/language
const insightCache: Record<string, string> = {};

export async function getMusicInsight(songTitle: string, artistName: string, lang: Language): Promise<string> {
  const cacheKey = `${songTitle}-${artistName}-${lang}`;

  if (insightCache[cacheKey]) {
    return insightCache[cacheKey];
  }

  let prompt = "";
  if (lang === 'mk') {
    prompt = `Ти си долгогодишен уредник на "Македонско народно радио". Напиши една длабока, поетска и инспиративна реченица на македонски јазик за песната "${songTitle}" од ${artistName}. Објасни како овој звук ги допира македонските корени, зошто е вечен дел од нашата душа и како ја чува светлината на традицијата. Користи возвишен, достоинствен и емотивен тон. Не користи повеќе од една реченица.`;
  } else if (lang === 'en') {
    prompt = `You are a veteran editor of "Macedonian Traditional & Folk Radio". Write a deep, poetic, and inspiring sentence in English about the song "${songTitle}" by ${artistName}. Explain how this sound touches Macedonian roots, why it is an eternal part of our soul, and how it preserves the light of tradition. Use a sublime, dignified, and emotional tone. Do not use more than one sentence.`;
  } else if (lang === 'ru') {
    prompt = `Вы — опытный редактор «Македонского народного радио». Напишите одну глубокую, поэтичную и вдохновляющую фразу на русском языке о песне «${songTitle}» в исполнении ${artistName}. Объясните, как этот звук затрагивает македонские корни, почему он является вечной частью нашей души и как он хранит свет традиции. Используйте возвышенный, достойный и эмоциональный тон. Используйте не более одного предложения.`;
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.9,
        topP: 0.95,
      },
    });

    const result = response.text?.trim() || getDefaultFallback(lang);
    insightCache[cacheKey] = result;
    return result;
  } catch (error: any) {
    console.warn("Gemini API Error:", error?.message || error);
    return getDefaultFallback(lang);
  }
}

function getDefaultFallback(lang: Language): string {
  const fallbacksMk = [
    "Оваа песна е огниште на кое се греат генерации Македонци низ вековите.",
    "Звук кој извира од длабочината на земјата и се искачува до небесните висини на духот.",
    "Во секој тон на оваа песна е запишана историјата на нашиот непокор и љубов.",
    "Мелос кој ја преточува болката во убавина, а минатото во вечно сеќавање."
  ];

  const fallbacksEn = [
    "This song is a hearth where generations of Macedonians have warmed their souls throughout the centuries.",
    "A sound that springs from the depths of the earth and climbs to the celestial heights of the spirit.",
    "In every note of this song, the history of our resilience and love is inscribed.",
    "Melodies that transform pain into beauty, and the past into eternal memory."
  ];

  const fallbacksRu = [
    "Эта песня — очаг, у которого согреваются поколения македонцев на протяжении веков.",
    "Звук, рождающийся в недрах земли и поднимающийся к небесным вершинам духа.",
    "В каждой ноте этой песни записана история нашей стойкости и любви.",
    "Мелос, превращающий боль в красоту, а прошлое — в вечную память."
  ];

  const pool = lang === 'mk' ? fallbacksMk : (lang === 'en' ? fallbacksEn : fallbacksRu);
  return pool[Math.floor(Math.random() * pool.length)];
}

