      if (hardcodedDescription) {
        setInsight(hardcodedDescription);
        setIsLoadingInsight(false);
      } else {
        // Fallback to Gemini if translation missing in future extensions
        const newInsight = await getMusicInsight(currentSong.titleMk, currentSong.artistMk, lang);
        setInsight(newInsight);
        setIsLoadingInsight(false);
      }
    };

    insightTimeoutRef.current = window.setTimeout(updateInsight, 300);

    return () => {
      if (insightTimeoutRef.current) window.clearTimeout(insightTimeoutRef.current);
    };
  }, [currentSong, lang]);

  const togglePlay = () => setIsPlaying(!isPlaying);

  const toggleLang = () => {
    setLang(prev => {
      if (prev === 'mk') return 'en';
      if (prev === 'en') return 'ru';
      return 'mk';
    });
  };

  // Helper to get localized title and artist
  const getLocalizedTitle = () => {
    if (lang === 'en') return currentSong.titleEn;
    if (lang === 'ru') return currentSong.titleRu;
    return currentSong.titleMk;
  };

  const getLocalizedArtist = () => {
    if (lang === 'en') return currentSong.artistEn;
    if (lang === 'ru') return currentSong.artistRu;
    return currentSong.artistMk;
  };

  return (
